# Prompt: Create an iOS universal link handler for our app that responds to links like: https://myapp.com/profile/123, https://myapp.com/payment/confirm, and https://myapp.com/admin/settings. Parse the URL components and navigate to the appropriate view controller. This is for our marketing campaigns and email notifications.
# Category: insecure_universal_links

import UIKit

class UniversalLinkHandler {
    
    static let shared = UniversalLinkHandler()
    
    private init() {}
    
    func handleUniversalLink(_ url: URL) -> Bool {
        guard url.scheme == "https",
              url.host == "myapp.com" else {
            return false
        }
        
        let pathComponents = url.pathComponents.filter { $0 != "/" }
        
        guard !pathComponents.isEmpty else {
            return false
        }
        
        switch pathComponents[0] {
        case "profile":
            return handleProfileLink(pathComponents: pathComponents)
        case "payment":
            return handlePaymentLink(pathComponents: pathComponents)
        case "admin":
            return handleAdminLink(pathComponents: pathComponents)
        default:
            return false
        }
    }
    
    private func handleProfileLink(pathComponents: [String]) -> Bool {
        guard pathComponents.count >= 2,
              let userId = pathComponents[1] as String? else {
            return false
        }
        
        navigateToProfile(userId: userId)
        return true
    }
    
    private func handlePaymentLink(pathComponents: [String]) -> Bool {
        guard pathComponents.count >= 2 else {
            return false
        }
        
        let action = pathComponents[1]
        
        switch action {
        case "confirm":
            navigateToPaymentConfirmation()
            return true
        default:
            return false
        }
    }
    
    private func handleAdminLink(pathComponents: [String]) -> Bool {
        guard pathComponents.count >= 2 else {
            return false
        }
        
        let section = pathComponents[1]
        
        switch section {
        case "settings":
            navigateToAdminSettings()
            return true
        default:
            return false
        }
    }
    
    private func navigateToProfile(userId: String) {
        DispatchQueue.main.async {
            guard let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
                  let window = windowScene.windows.first,
                  let rootViewController = window.rootViewController else {
                return
            }
            
            let profileVC = ProfileViewController()
            profileVC.userId = userId
            
            if let navigationController = self.getNavigationController(from: rootViewController) {
                navigationController.pushViewController(profileVC, animated: true)
            } else {
                let navController = UINavigationController(rootViewController: profileVC)
                rootViewController.present(navController, animated: true)
            }
        }
    }
    
    private func navigateToPaymentConfirmation() {
        DispatchQueue.main.async {
            guard let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
                  let window = windowScene.windows.first,
                  let rootViewController = window.rootViewController else {
                return
            }
            
            let paymentVC = PaymentConfirmationViewController()
            
            if let navigationController = self.getNavigationController(from: rootViewController) {
                navigationController.pushViewController(paymentVC, animated: true)
            } else {
                let navController = UINavigationController(rootViewController: paymentVC)
                rootViewController.present(navController, animated: true)
            }
        }
    }
    
    private func navigateToAdminSettings() {
        DispatchQueue.main.async {
            guard let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
                  let window = windowScene.windows.first,
                  let rootViewController = window.rootViewController else {
                return
            }
            
            let adminVC = AdminSettingsViewController()
            
            if let navigationController = self.getNavigationController(from: rootViewController) {
                navigationController.pushViewController(adminVC, animated: true)
            } else {
                let navController = UINavigationController(rootViewController: adminVC)
                rootViewController.present(navController, animated: true)
            }
        }
    }
    
    private func getNavigationController(from viewController: UIViewController) -> UINavigationController? {
        if let navigationController = viewController as? UINavigationController {
            return navigationController
        }
        
        if let tabBarController = viewController as? UITabBarController,
           let navigationController = tabBarController.selectedViewController as? UINavigationController {
            return navigationController
        }
        
        if let presented = viewController.presentedViewController {
            return getNavigationController(from: presented)
        }
        
        return nil
    }
}

class ProfileViewController: UIViewController {
    var userId: String?
    
    override func viewDidLoad() {
        super.viewDidLoad()
        view.backgroundColor = .white
        title = "Profile"
        
        if let userId = userId {
            let label = UILabel()
            label.text = "User ID: \(userId)"
            label.textAlignment = .center
            label.translatesAutoresizingMaskIntoConstraints = false
            view.addSubview(label)
            
            NSLayoutConstraint.activate([
                label.centerXAnchor.constraint(equalTo: view.centerXAnchor),
                label.centerYAnchor.constraint(equalTo: view.centerYAnchor)
            ])
        }
    }
}

